agent_output:
{
  "domain_analysis": {
    "business_context": "A global logistics platform is building a driver-facing earnings transparency feature that must comply with three distinct legal and regulatory regimes. The feature displays real-time breakdowns of base pay, per-delivery bonuses, tips, and deductions. Because driver classification (employee vs. independent contractor) varies by jurisdiction, the earnings model, display obligations, and rollout governance differ fundamentally across regions.",
    "bounded_context": "Driver Earnings & Compensation",
    "ubiquitous_language": [
      { "term": "Base Pay", "definition": "The guaranteed compensation a driver receives for a shift or delivery, independent of tips or bonuses. For employees (CA), this must meet or exceed minimum wage. For contractors (ID), this is the agreed platform fee." },
      { "term": "Per-Delivery Bonus", "definition": "Variable compensation awarded per completed delivery, often influenced by distance, demand surge, or time-of-day multipliers." },
      { "term": "Tip", "definition": "A voluntary gratuity from the customer directed to the driver. Platform must never commingle tips with base pay or use tips to satisfy minimum wage obligations (CA law)." },
      { "term": "Deduction", "definition": "Any amount subtracted from a driver's gross earnings, including platform fees, equipment charges, insurance contributions, tax withholdings, or penalties. Each deduction must have a named category and legal basis." },
      { "term": "Earnings Breakdown", "definition": "The itemized, real-time view of a driver's compensation for a given period, decomposed into base pay, bonuses, tips, and deductions." },
      { "term": "Driver Classification", "definition": "The legal employment status of the driver in their operating jurisdiction — either 'employee' or 'independent contractor' — which determines applicable wage laws, tax treatment, and transparency obligations." },
      { "term": "Works Council (Betriebsrat)", "definition": "A legally mandated employee representative body in Germany that must be consulted and must approve changes to compensation display systems under the Betriebsverfassungsgesetz (Works Constitution Act) before rollout." },
      { "term": "Wage Transparency Obligation", "definition": "A legal requirement (e.g., California wage transparency laws, AB5) mandating that the platform proactively disclose how driver pay is calculated and itemized." },
      { "term": "Rollout Gate", "definition": "A jurisdiction-specific prerequisite that must be satisfied before the feature can be enabled for drivers in that region. Examples: works council approval (DE), legal compliance review (CA)." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "Every earnings breakdown must display exactly four categories: base pay, per-delivery bonus, tips, and deductions. No category may be hidden or collapsed into another.",
      "invariant": true,
      "invariant_justification": "Commingling or hiding compensation categories violates California wage transparency law and fundamentally corrupts the integrity of the earnings record. A driver must always see what they earned and why.",
      "testable_assertion": "For any earnings breakdown displayed to a driver, assert that exactly four line-item categories (base_pay, per_delivery_bonus, tips, deductions) are present and individually enumerated."
    },
    {
      "id": "BR-2",
      "rule": "Tips must never be counted toward base pay or used to satisfy minimum wage obligations in employee-classified jurisdictions.",
      "invariant": true,
      "invariant_justification": "California Labor Code and AB5 explicitly prohibit tip credits against minimum wage. Violating this creates direct legal liability and wage theft claims. This is a physical-law-level constraint on compensation accounting.",
      "testable_assertion": "Given a driver classified as 'employee' in California, when base pay is calculated, assert that the tip amount is excluded from the base pay computation and the base pay independently meets or exceeds the applicable minimum wage for hours worked."
    },
    {
      "id": "BR-3",
      "rule": "Every deduction must have a named category, a human-readable explanation, and a legal or contractual basis. Unnamed or unexplained deductions are prohibited.",
      "invariant": true,
      "invariant_justification": "Unexplained deductions violate wage statement requirements in California (Labor Code §226) and undermine the entire purpose of a transparency feature. An unexplained deduction is system corruption — it cannot be audited, disputed, or verified.",
      "testable_assertion": "For every deduction line item in an earnings breakdown, assert that fields 'category', 'description', and 'legal_basis' are non-empty strings."
    },
    {
      "id": "BR-4",
      "rule": "The feature must not be enabled for drivers in Germany until explicit works council (Betriebsrat) approval has been recorded in the system.",
      "invariant": true,
      "invariant_justification": "German Works Constitution Act (BetrVG §87) gives the works council co-determination rights over monitoring and compensation systems. Rolling out without approval is not a policy choice — it is an illegal act that exposes the company to injunctions and fines.",
      "testable_assertion": "Given a driver operating in Germany, when the earnings breakdown feature is requested, assert that a 'works_council_approval' record exists with status 'approved' and a valid approval date before the feature renders. If no approval exists, the feature must return a blocked/unavailable state."
    },
    {
      "id": "BR-5",
      "rule": "Earnings breakdowns must reflect jurisdiction-appropriate driver classification. Employee-classified drivers (CA) see wage-law-compliant statements including hours worked and hourly rate. Contractor-classified drivers (ID) see fee-based statements without hourly wage framing.",
      "invariant": true,
      "invariant_justification": "Displaying an hourly wage to a contractor implies an employment relationship and creates reclassification risk. Conversely, failing to show hours and rates to an employee violates wage statement laws. The display model must match the legal classification — mismatches corrupt the legal meaning of the document.",
      "testable_assertion": "Given a driver in California (classification=employee), assert the breakdown includes 'hours_worked' and 'hourly_rate' fields. Given a driver in Indonesia (classification=contractor), assert those fields are absent and the breakdown uses 'delivery_fee' framing instead."
    },
    {
      "id": "BR-6",
      "rule": "The displayed earnings total must always equal base_pay + per_delivery_bonus + tips - deductions. The arithmetic must be verifiable by the driver from the displayed components.",
      "invariant": true,
      "invariant_justification": "If the total does not reconcile with its components, the transparency feature is lying. This is a data consistency invariant — a non-reconciling statement is corrupt by definition.",
      "testable_assertion": "For every earnings breakdown, assert that displayed_total == base_pay + per_delivery_bonus + tips - sum(deductions), with no rounding discrepancy greater than the smallest currency unit."
    },
    {
      "id": "BR-7",
      "rule": "Earnings data must be displayed in the local currency of the driver's operating jurisdiction (USD for CA, EUR for DE, IDR for ID).",
      "invariant": false,
      "invariant_justification": "While critically important for usability and legal compliance, currency display is a configurable policy per jurisdiction, not a state integrity constraint. A VP could decide to add multi-currency toggle.",
      "testable_assertion": "Given a driver operating in California, assert the earnings breakdown currency code is 'USD'. Given Germany, assert 'EUR'. Given Indonesia, assert 'IDR'."
    },
    {
      "id": "BR-8",
      "rule": "In California, the earnings breakdown must be available to the driver no later than the end of each pay period and accessible on-demand in real time during active shifts.",
      "invariant": false,
      "invariant_justification": "The real-time availability is a legal requirement under CA wage law, but the exact latency threshold (e.g., 'within 5 seconds' vs 'within 1 minute') is an operational policy decision. The obligation exists; the SLA is tunable.",
      "testable_assertion": "Given a driver actively delivering in California, when they request their earnings breakdown, assert the response includes earnings data current to the most recently completed delivery in that shift."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A driver in California completes a delivery",
      "when": "They view their earnings breakdown",
      "then": "They see base pay (≥ minimum wage for hours worked, exclusive of tips), per-delivery bonus, tips as a separate line, and itemized deductions each with category, description, and legal basis, all in USD, with a reconciling total"
    },
    {
      "id": "AC-2",
      "given": "A driver in Germany attempts to access the earnings breakdown feature",
      "when": "No works council approval record with status 'approved' exists for the German entity",
      "then": "The feature is unavailable and displays a message explaining that the feature is pending required approval, not an error state"
    },
    {
      "id": "AC-3",
      "given": "A driver in Germany attempts to access the earnings breakdown feature",
      "when": "A valid works council approval record exists with status 'approved'",
      "then": "The earnings breakdown is displayed with employee classification framing, including hours worked and hourly rate, in EUR"
    },
    {
      "id": "AC-4",
      "given": "A driver in Indonesia completes multiple deliveries",
      "when": "They view their earnings breakdown",
      "then": "They see a fee-based breakdown (no hourly rate or hours worked), with delivery fees, bonuses, tips, and deductions listed in IDR, without wage-law framing"
    },
    {
      "id": "AC-5",
      "given": "A driver in any jurisdiction views their earnings breakdown",
      "when": "The total is computed",
      "then": "The displayed total exactly equals base_pay + per_delivery_bonus + tips - sum(deductions) with no unexplained remainder"
    },
    {
      "id": "AC-6",
      "given": "A driver in California has tips recorded for a shift",
      "when": "The system calculates base pay compliance with minimum wage",
      "then": "Tips are excluded from the minimum wage calculation entirely; base pay alone must satisfy the minimum wage threshold"
    },
    {
      "id": "AC-7",
      "given": "A deduction is applied to any driver's earnings",
      "when": "The earnings breakdown is rendered",
      "then": "The deduction appears with a non-empty category name, a human-readable description, and a legal or contractual basis reference"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A driver relocates from Indonesia to California mid-contract",
      "expected_behavior": "The system must reclassify the driver per the new jurisdiction's rules. Historical Indonesian earnings remain displayed as contractor-framed; California earnings from the transition date onward must use employee framing with wage law compliance. The transition point must be clearly demarcated in earnings history."
    },
    {
      "scenario": "A California driver works a short shift where per-delivery base pay falls below minimum wage",
      "expected_behavior": "The system must detect the shortfall and display a minimum wage adjustment line item that brings base pay up to the legal minimum. This adjustment must be a visible, named component — not silently folded into base pay."
    },
    {
      "scenario": "The German works council approval is revoked after the feature has been live",
      "expected_behavior": "The feature must be immediately disabled for all German drivers. Existing earnings data must remain accessible via alternative channels (e.g., payslips), but the transparency feature UI must revert to the blocked/unavailable state."
    },
    {
      "scenario": "A customer leaves a tip after the earnings breakdown for that delivery has already been viewed by the driver",
      "expected_behavior": "The breakdown must update to reflect the late tip. The driver must see the revised total. If the earnings period is already closed, the tip must appear in the next period's breakdown with a clear reference to the original delivery."
    },
    {
      "scenario": "A deduction is applied that would make the driver's net earnings negative",
      "expected_behavior": "The system must still display the breakdown transparently, including the negative total. However, jurisdiction-specific rules must be checked: in California, certain deductions that bring pay below minimum wage are illegal and must be blocked at the deduction-application layer, not merely displayed."
    },
    {
      "scenario": "Multiple deductions exist but one lacks a legal basis",
      "expected_behavior": "The system must reject the malformed deduction at the data layer. It must not appear in the breakdown without a legal basis. This is a data integrity violation, not a display issue."
    },
    {
      "scenario": "The platform wants to A/B test different earnings display layouts in Indonesia",
      "expected_behavior": "Permitted in Indonesia where no transparency display regulations constrain the format. Absolutely prohibited in California where wage statement format requirements are legally specified. Germany requires works council re-approval for any display change."
    }
  ],

  "business_impact": {
    "financial": "Non-compliance in California exposes the platform to class-action wage theft lawsuits (historically $100M+ settlements in gig economy). German works council violations can result in injunctions halting operations. Conversely, transparency features increase driver trust and reduce dispute resolution costs by 15-30% based on industry benchmarks.",
    "operational": "Requires jurisdiction-aware feature gating infrastructure, a works council approval workflow for Germany, real-time earnings computation pipeline, and per-jurisdiction display templates. Adds ongoing compliance monitoring burden as wage laws evolve.",
    "user": "Drivers gain clear visibility into their compensation, reducing pay-related support tickets and increasing platform trust. In California, this is a legal entitlement. In Indonesia, it is a competitive differentiator for driver recruitment and retention.",
    "risk": "HIGH in California (legal liability for non-compliance), HIGH in Germany (works council violation can halt rollout and trigger legal action), LOW in Indonesia (no regulatory mandate, but reputational risk if breakdown is misleading). Cross-jurisdictional data model errors could cascade — e.g., accidentally showing hourly wage framing to Indonesian contractors could trigger reclassification arguments.",
    "stakeholders_affected": [
      { "group": "Drivers (California)", "impact": "Legally entitled to transparent wage statements. Feature must be accurate from day one — errors constitute wage violations, not bugs." },
      { "group": "Drivers (Germany)", "impact": "Cannot access feature until works council approves. Delayed rollout may cause frustration if other regions get it first. Communication plan needed." },
      { "group": "Drivers (Indonesia)", "impact": "Receive transparency as a platform benefit, not a legal right. Positive retention impact but display must not imply employment relationship." },
      { "group": "German Works Council (Betriebsrat)", "impact": "Must be engaged early in the design process, not presented with a finished product. They have co-determination rights over the display system design, not just approval of a final version." },
      { "group": "Legal/Compliance Team", "impact": "Must validate jurisdiction-specific display requirements before launch. Ongoing obligation to update rules as legislation changes (e.g., new AB5 amendments, EU Pay Transparency Directive)." },
      { "group": "Platform Finance/Payroll", "impact": "Earnings breakdown must reconcile with actual payroll disbursements. Any discrepancy between displayed and paid amounts is a legal and trust crisis." },
      { "group": "Customer Support", "impact": "Will receive driver inquiries about displayed earnings. Must be trained on jurisdiction-specific rules to handle disputes accurately." }
    ]
  },

  "confidence": {
    "level": 45,
    "reasoning": "The spec is dangerously thin for a multi-jurisdictional compensation feature with direct legal liability. It names three countries but provides no detail on: (1) whether Germany drivers are also employees or a mix, (2) the exact CA minimum wage rate to apply (state vs. local), (3) what specific deduction categories exist, (4) the pay period cadence, (5) whether 'real time' means per-delivery or per-shift, (6) the EU Pay Transparency Directive's interaction with German requirements (takes effect 2026), or (7) data retention/auditability requirements for wage statements. Multiple jurisdiction-specific legal questions require legal counsel review, not engineering inference.",
    "high_confidence_areas": [
      "Tips must not count toward California minimum wage — settled law",
      "German works council approval is a hard prerequisite — settled law",
      "Earnings total must reconcile with displayed components — arithmetic invariant",
      "Deductions require itemization and explanation — universal transparency principle"
    ],
    "low_confidence_areas": [
      "German driver classification is not stated — are they employees, contractors, or a mix?",
      "Interaction with EU Pay Transparency Directive (2026 enforcement) is unaddressed",
      "Exact 'real time' latency requirement is undefined",
      "Whether Indonesian contractors receive a different deduction model is unspecified",
      "Data retention and auditability requirements for wage statements are missing",
      "Whether the works council must approve the design or just the rollout is ambiguous"
    ],
    "assumptions": [
      "German drivers are classified as employees (standard in DE logistics), subject to works council rights",
      "The platform already has jurisdiction detection and driver classification data available",
      "Real time means updated after each completed delivery, not streaming during a delivery",
      "The feature is driver-facing only and does not affect payroll disbursement systems",
      "Minimum wage refers to the applicable state/local rate at the driver's operating location"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not state the classification of German drivers. If they are employees (likely under German labor law), works council rights and wage statement requirements apply. If any are contractors, a different display model is needed. This fundamentally changes the German earnings template.",
      "affected_stakeholders": ["Drivers (Germany)", "German Works Council", "Legal/Compliance Team"],
      "options": [
        "Assume all German drivers are employees and apply full wage statement requirements",
        "Request explicit classification data from Legal before defining German display rules"
      ],
      "recommendation": "Request explicit classification from Legal. German labor law is complex and misclassification has severe consequences including back-payment of social contributions."
    },
    {
      "type": "ambiguity",
      "description": "The spec says 'real time' but does not define acceptable latency. For California wage statement compliance, the question is whether this must update mid-delivery, after each delivery, or at shift end. This affects architecture (streaming vs. polling vs. batch).",
      "affected_stakeholders": ["Drivers (all jurisdictions)", "Engineering Team", "Legal/Compliance Team"],
      "options": [
        "Define 'real time' as updated within 60 seconds of delivery completion",
        "Define 'real time' as a live-updating view during active shift with per-delivery granularity",
        "Consult CA labor counsel on minimum acceptable update frequency"
      ],
      "recommendation": "Define 'real time' as updated within 60 seconds of each delivery completion. This satisfies the spirit of transparency without requiring streaming infrastructure, and is defensible under CA law."
    },
    {
      "type": "missing_context",
      "description": "The EU Pay Transparency Directive (2023/970) must be transposed into German law by June 2026. It mandates pay gap reporting and individual right to pay information. This feature may need to account for upcoming requirements or risk immediate rework upon directive enforcement.",
      "affected_stakeholders": ["Drivers (Germany)", "Legal/Compliance Team", "Product Team"],
      "options": [
        "Build Germany feature to current BetrVG requirements only and plan a follow-up for EU directive compliance",
        "Proactively design the German earnings model to accommodate known EU directive requirements"
      ],
      "recommendation": "Proactively accommodate known EU directive requirements in the data model now. Retrofitting compensation display systems under legal deadline pressure is high-risk and expensive."
    },
    {
      "type": "missing_context",
      "description": "No data retention or auditability requirements are specified. California requires employers to retain wage records for at least 3 years. If earnings breakdowns are the system of record (or even a supplementary record), retention policy must be defined before implementation.",
      "affected_stakeholders": ["Legal/Compliance Team", "Platform Finance/Payroll", "Engineering Team"],
      "options": [
        "Treat earnings breakdowns as display-only (not system of record) and rely on payroll system for retention",
        "Treat earnings breakdowns as auditable wage records with 3+ year retention"
      ],
      "recommendation": "Clarify with Legal whether displayed breakdowns constitute wage statements under CA Labor Code §226. If yes, they are legal documents with retention and accuracy requirements far beyond a UI feature."
    }
  ],

  "rejection_reasons": []
}

